      <div class="panel-kicker">可视化总结</div>
      <div class="panel-title">{{ parsedSummary.title || `楼层 ${parsedSummary.range.start}-${parsedSummary.range.end}` }}</div>
      <div class="panel-meta">
        <span>楼层 {{ parsedSummary.range.start }} - {{ parsedSummary.range.end }}</span>
        <span v-if="parsedSummary.time">· {{ parsedSummary.time }}</span>
        <span v-if="parsedSummary.location">· {{ parsedSummary.location }}</span>
      </div>
    </div>

    <section v-if="parsedSummary.overview" class="summary-card">
      <div class="card-title"><i class="fa-solid fa-align-left"></i> 剧情概览</div>
      <div class="card-text">{{ parsedSummary.overview }}</div>
    </section>

    <section v-if="parsedSummary.events.length" class="summary-card">
      <div class="card-title"><i class="fa-solid fa-list-check"></i> 重要事件</div>
      <ol class="event-list">
        <li v-for="(event, index) in parsedSummary.events" :key="`event-${index}`">{{ event }}</li>
      </ol>
    </section>

    <section v-if="parsedSummary.characters.length" class="summary-card">
      <div class="card-title"><i class="fa-solid fa-users"></i> 角色状态</div>
      <div v-for="(character, index) in parsedSummary.characters" :key="`character-${index}`" class="nested-card">
        <div class="nested-title">{{ character.name || '未知角色' }}</div>
        <div v-if="character.status" class="field-line"><span>状态</span>{{ character.status }}</div>
        <div v-if="character.attitude" class="field-line"><span>态度</span>{{ character.attitude }}</div>
        <div v-if="character.memory" class="field-line"><span>记忆</span>{{ character.memory }}</div>
      </div>
    </section>

    <section v-if="parsedSummary.relationshipChanges.length" class="summary-card">
      <div class="card-title"><i class="fa-solid fa-link"></i> 关系变化</div>
      <div v-for="(relation, index) in parsedSummary.relationshipChanges" :key="`relation-${index}`" class="nested-card">
        <div class="nested-title">{{ relation.from || '未知' }} → {{ relation.to || '未知' }}</div>
        <div v-if="relation.change" class="field-line"><span>变化</span>{{ relation.change }}</div>
        <div v-if="relation.reason" class="field-line"><span>原因</span>{{ relation.reason }}</div>
      </div>
    </section>

    <section v-if="parsedSummary.foreshadowing.length || parsedSummary.todo.length" class="summary-card two-cols">
      <div v-if="parsedSummary.foreshadowing.length">
        <div class="card-title"><i class="fa-solid fa-puzzle-piece"></i> 伏笔</div>
        <ul class="bullet-list">
          <li v-for="(item, index) in parsedSummary.foreshadowing" :key="`foreshadow-${index}`">{{ item }}</li>
        </ul>
      </div>
      <div v-if="parsedSummary.todo.length">
        <div class="card-title"><i class="fa-solid fa-clock"></i> 待跟进</div>
        <ul class="bullet-list">
          <li v-for="(item, index) in parsedSummary.todo" :key="`todo-${index}`">{{ item }}</li>
        </ul>
      </div>
    </section>

    <section v-if="parsedSummary.worldbookCandidates.length" class="summary-card">
      <div class="card-title"><i class="fa-solid fa-book"></i> 世界书候选</div>
      <div v-for="(candidate, index) in parsedSummary.worldbookCandidates" :key="`wb-${index}`" class="nested-card">
        <div class="nested-title">
          <span :class="candidate.enabled ? 'enabled-tag' : 'disabled-tag'">{{ candidate.enabled ? '写入' : '跳过' }}</span>
          {{ candidate.title || '未命名' }}
          <span class="type-tag">{{ candidate.type }}</span>
        </div>
        <div v-if="candidate.content" class="card-text">{{ candidate.content }}</div>
      </div>
    </section>
  </div>
</template>

